import{c as a,Q as o,j as t,m as s}from"./chunks/framework.rlpw0eGz.js";const m=JSON.parse('{"title":"Desktop Installation","description":"","frontmatter":{},"headers":[],"relativePath":"installation/desktop.md","filePath":"installation/desktop.md","lastUpdated":1778736656000}'),l={name:"installation/desktop.md"};function n(r,e,i,d,p,c){return o(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="desktop-installation" tabindex="-1">Desktop Installation <a class="header-anchor" href="#desktop-installation" aria-label="Permalink to &quot;Desktop Installation&quot;">​</a></h1><p>Memoh Desktop is the native client for personal and local use. It is separate from the server deploy stack: the desktop app manages its own local backend instead of connecting to a hosted Web/server deployment by default.</p><h2 id="when-to-use-desktop" tabindex="-1">When to use Desktop <a class="header-anchor" href="#when-to-use-desktop" aria-label="Permalink to &quot;When to use Desktop&quot;">​</a></h2><p>Choose Desktop when you want:</p><ul><li>a local app that starts Memoh for you</li><li>single-user or personal workflows</li><li>local memory and local storage</li><li>a bundled <code>memoh</code> CLI connected to the same local server</li><li>local or Docker-backed workspaces from your own machine</li></ul><p>Choose <a href="/installation/docker.html">Server Deploy</a> instead when you need shared access, production uptime, remote users, or messaging channels that should keep running while your desktop is offline.</p><h2 id="install" tabindex="-1">Install <a class="header-anchor" href="#install" aria-label="Permalink to &quot;Install&quot;">​</a></h2><ol><li>Download the installer for your platform from the <a href="https://memoh.ai/desktop" target="_blank" rel="noreferrer">Memoh Desktop download page</a>.</li><li>Open Memoh.</li><li>Let the app start its local server and initialize storage.</li><li>Optional: use the app menu to install the bundled <code>memoh</code> CLI.</li></ol><h2 id="what-desktop-manages" tabindex="-1">What Desktop manages <a class="header-anchor" href="#what-desktop-manages" aria-label="Permalink to &quot;What Desktop manages&quot;">​</a></h2><p>Desktop owns the local runtime lifecycle:</p><ul><li>local <code>memoh-server</code> on <code>127.0.0.1:18731</code></li><li>SQLite-backed local data under the OS application data directory</li><li>embedded Qdrant for memory vector search</li><li>bundled CLI, server binary, provider templates, and workspace bridge runtime</li><li>system tray reopen and quit behavior</li></ul><p>Quitting from the tray follows the desktop shutdown path and stops the managed local server and embedded Qdrant.</p><h2 id="workspace-behavior" tabindex="-1">Workspace behavior <a class="header-anchor" href="#workspace-behavior" aria-label="Permalink to &quot;Workspace behavior&quot;">​</a></h2><p>Desktop can use trusted local workspaces and container-backed workspaces depending on configuration and runtime availability. Trusted local workspaces run with local user permissions and are not container-isolated. Container-backed workspaces keep the normal bot workspace model for file editing, command execution, MCP hosting, and optional display/browser sessions.</p><p>For runtime details, see <a href="/installation/workspace-backends.html">Workspace Backends</a>.</p>',15)])])}const k=a(l,[["render",n]]);export{m as __pageData,k as default};
